import React, { useEffect } from "react";
import { useQuery } from "@tanstack/react-query";

import "./HomePage.css";
import Main from "../../Components/Main/Main";
import Home from "../../Components/Home/Home";
import Loading from "../../Components/Loading/Loading.jsx";

function HomePage() {
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  const {
    data: homeData,
    isLoading: isLoadingHome,
    isSuccess: isSuccessHome,
    error: homeError,
  } = useQuery({
    queryKey: ["home"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/Home").then((res) => res.json()),
  });

  const {
    data: productsData,
    isLoading: isLoadingProducts,
    isSuccess: isSuccessProducts,
    error: productsError,
  } = useQuery({
    queryKey: ["products"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/AllProducts").then((res) => res.json()),
  });

  const isLoading = isLoadingHome || isLoadingProducts;
  const error = homeError || productsError;

  return (
    <div className="background">
      {isLoading && <Loading />}
      {error && <p>Error: {error.message}</p>}
      {!isLoading && (
        <>
          <Home data={homeData} isSuccess={isSuccessHome} />
          <Main data={productsData} isSuccess={isSuccessProducts} />
        </>
      )}
    </div>
  );
}

export default HomePage;
